css:
@import url('https://fonts.googleapis.com/css2?family=Courier+Prime:wght@400;700&display=swap');

/* REMOVE DEFAULT FRAPPE STYLES */
.print-format input,
.print-format select,
.print-format textarea,
.print-format .form-control,
.print-format .like-disabled-input,
.print-format [class*="input"],
.meta-section span,
.meta-section div,
.doc-ref-row span,
.doc-ref-row div,
.footer-section span,
.footer-section div,
.process-header span,
.process-header div {
  border: none !important;
  box-shadow: none !important;
  background: transparent !important;
  padding: 0 !important;
  outline: none !important;
}

/* GLOBAL */
*{
  margin:0;
  padding:0;
  box-sizing:border-box;
}

body,
.print-format{
  font-size:8pt;
  color:#000;
  background:#fff;
  font-family:'Courier Prime', monospace;
}

.label{
  font-size:9pt !important;
  font-weight:700;
}

/* MAIN WRAPPER */
.cert-wrapper{
  width:100%;
  margin:auto;
  padding:6mm 8mm;
  border:2px solid #000 !important;
  border-top:2px solid #000 !important;
  background:#fff;
}

/* HEADER */
.doc-ref-row{
  display:flex;
  justify-content:space-between;
  align-items:center;
  border-bottom:1px solid #000;
  padding:2px 0;
}

.cert-title{
  font-size:13pt;
  font-weight:700;
  text-decoration:underline;
  text-align:center;
  flex:1;
  letter-spacing:1px;
}

.cert-no{
  font-size:8.5pt;
  font-weight:700;
}

/* META SECTION */
.meta-section{
  border-bottom:1px solid #000;
  padding:4px 0;
}

.meta-row-flex{
  display:flex;
  justify-content:space-between;
  margin-bottom:4px;
}

.meta-col{
  width:48%;
  text-align:left;
}

.meta-col-full{
  width:100%;
}

.val{
  font-weight:400;
}

/* TABLE COMMON */
.test-table,
.process-table,
.traverse-table{
  width:100%;
  border-collapse:collapse;
}

/* TEST TABLE */
.test-table{
  border-bottom:1.5px solid #000;
  font-size:8.5pt;
}

.test-table th{
  border:1px solid #000;
  text-align:center;
  padding:2px 4px;
  font-weight:700;
  background:#f5f5f5;
  line-height:1.3;
}

.test-table td{
  border:1px solid #000;
  padding:2px 5px;
  text-align:center;
  vertical-align:middle;
  line-height:1.5;
}

.test-table td.left{
  text-align:left;
  font-weight:700;
}

/* GRAPH SECTION */
.graph-section{
  border-bottom:1.5px solid #000;
  padding:4px 0;
  display:flex;
  gap:4px;
  overflow:hidden;
}

.graph-left{
  flex:0 0 75mm;
  border-right:1px solid #ccc;
  padding-right:4px;
  min-width:0;
}

.graph-right{
  flex:1;
  padding-left:4px;
  font-size:7.5pt;
  min-width:0;
  overflow:hidden;
}

/* TRAVERSE TABLE */
.traverse-table{
  font-size:6pt;
  margin-bottom:6px;
}

.traverse-table td{
  border:1px solid #000;
  padding:1px;
  text-align:center;
  white-space:nowrap;
}

.traverse-table td.traverse-label{
  font-weight:700;
  background:#f5f5f5;
  width:6mm;
}

/* OTHER DETAILS */
.other-details{
  margin-top:5px;
  font-size:7.5pt;
}

/* PROCESS SECTION */
.process-section{
  border-bottom:1.5px solid #000;
}

.process-header{
  display:flex;
  gap:6px;
  padding:2px 0;
  font-size:8.5pt;
  border-bottom:1px solid #000;
}

.process-table{
  font-size:8.5pt;
}

.process-table th{
  border:1px solid #000;
  padding:2px 6px;
  text-align:center;
  font-weight:700;
  background:#f5f5f5;
}

.process-table td{
  border:1px solid #000;
  padding:2px 6px;
  text-align:center;
  height:16px;
}

/* MICROSTRUCTURE */
.micro-section{
  border-bottom:1.5px solid #000;
}

.micro-header-row{
  display:flex;
  border-bottom:1px solid #000;
}

.micro-header-cell{
  flex:1;
  padding:2px 5px;
  font-weight:700;
  font-size:8.5pt;
  text-align:center;
  border-right:1px solid #000;
}

.micro-header-cell:last-child{
  border-right:none;
}

.micro-images-row{
  display:flex;
  min-height:44mm;
}

.micro-img-cell{
  flex:1;
  border-right:1px solid #000;
  padding:3px;
  display:flex;
  align-items:center;
  justify-content:center;
}

.micro-img-cell:last-child{
  border-right:none;
}

.micro-img-cell img{
  max-width:100%;
  max-height:40mm;
  object-fit:contain;
}

.micro-notes-row{
  display:flex;
}

.micro-note-cell{
  flex:1;
  padding:2px 5px;
  font-size:7.5pt;
  text-align:center;
  border-right:1px solid #000;
  font-style:italic;
}

.micro-note-cell:last-child{
  border-right:none;
}

/* FOOTER */
.footer-section{
  padding-top:3px;
  font-size:8.5pt;
}

.footer-row{
  display:flex;
  justify-content:space-between;
  line-height:1.8;
}

.footer-bottom{
  margin-top:8px;
}

.sign-box{
  text-align:center;
  font-size:8pt;
  min-width:120px;
}

/* PRINT */
@media print {

  @page{
    size:A4 portrait;
    margin:0;
  }

  body{
    margin:0;
  }

  .cert-wrapper{
    border:2px solid #000 !important;
    border-top:2px solid #000 !important;
    width:210mm;
    min-height:297mm;
    page-break-inside:avoid;
  }

}
